import React, { createContext, useState, useContext } from 'react';

const UserApplicationContext = createContext(null);

export const useUserApplication = () => {
  const context = useContext(UserApplicationContext);
  if (!context) {
    throw new Error('useUserApplication must be used within a UserApplicationProvider');
  }
  return context;
};

export const UserApplicationProvider = ({ children }) => {
  // Store user applications: { userId: { fullName, email, phone, address, nationalId, driverLicenseId, status, remarks, submittedAt } }
  const [applications, setApplications] = useState(() => {
    const stored = localStorage.getItem('userApplications');
    return stored ? JSON.parse(stored) : {};
  });

  const saveApplication = (userId, applicationData) => {
    const newApplications = {
      ...applications,
      [userId]: {
        ...applicationData,
        status: 'pending',
        remarks: '',
        submittedAt: new Date().toISOString()
      }
    };
    setApplications(newApplications);
    localStorage.setItem('userApplications', JSON.stringify(newApplications));
  };

  const getApplication = (userId) => {
    return applications[userId] || null;
  };

  const updateApplicationStatus = (userId, status, remarks) => {
    const newApplications = {
      ...applications,
      [userId]: {
        ...applications[userId],
        status,
        remarks,
        updatedAt: new Date().toISOString()
      }
    };
    setApplications(newApplications);
    localStorage.setItem('userApplications', JSON.stringify(newApplications));
  };

  const getAllApplications = () => {
    return Object.entries(applications).map(([userId, data]) => ({
      userId,
      ...data
    }));
  };

  const getPendingApplications = () => {
    return Object.entries(applications)
      .filter(([_, data]) => data.status === 'pending')
      .map(([userId, data]) => ({
        userId,
        ...data
      }));
  };

  const value = {
    applications,
    saveApplication,
    getApplication,
    updateApplicationStatus,
    getAllApplications,
    getPendingApplications
  };

  return (
    <UserApplicationContext.Provider value={value}>
      {children}
    </UserApplicationContext.Provider>
  );
};

export default UserApplicationContext;
